var javascript=function(){"use strict";return[{title:"调用栈",content:"调用栈是解析器（如浏览器中的的javascript解析器）的一种机制，可以在脚本调用多个函数时，跟踪每个函数在完成执行时应该返回控制的点。（如什么函数正在执行，什么函数被这个函数调用，下一个调用的函数是谁）"},{title:"局部变量和全局变量",content:"变量分为局部与全局，局部变量又可称之为内部变量。由某对象或某个函数所创建的变量通常都是局部变量，只能被内部引用，而无法被其它对象或函数引用。全局变量既可以是某对象函数创建，也可以是在本程序任何地方创建。全局变量是可以被本程序所有对象或函数引用。javascript 的全局变量一般会挂在 window 对象上。"},{title:"三元运算符",content:"三元运算符是软件编程中的一个固定格式，语法是“条件表达式 ? 表达式1 : 表达式2”。问号前面的条件表达式是判断的条件，判断结果为 bool 型，为true时调用表达式1，为false时调用表达式2。"},{title:"Cookie",content:"特指某些网站为了辨别用户身份、进行 session 跟踪而储存在用户本地终端上的数据（通常经过加密）。Cookie会在浏览器向服务器发送http请求时放在请求头里一起发送给服务器，这通常是很有用的，服务器可以根据Cookie判断该次请求的状态。"},{title:"单页面应用（SPA）",content:"单页面应用（SPA）是旨在对Web应用发动革命的软件运动中可信度很高的一种。此类应用有望进行更加模块化的开发，令应用更加容易地适配与多个设备，并拥有更好的应用生命周期管理——这些几乎是软件架构师希望的全部。SPA 使前端开发者拿到了监管url的权利，通过监听页面地址变化来调用前端模块，渲染不同页面。当然，前端这时也拥有了修改url的能力。管理好前端视图与url，整个单页面就已经架构完成。"}]}();